        'infty': '∞', 'partial': '∂', 'nabla': '∇',
        'angle': '∠', 'measuredangle': '∡', 'triangle': '△',
        'perp': '⊥', 'parallel': '∥', 'nparallel': '∦',
        'therefore': '∴', 'because': '∵',
        'ldots': '…', 'cdots': '⋯', 'vdots': '⋮', 'ddots': '⋱', 'dots': '…',
        'prime': '′', 'degree': '°',
        'ell': 'ℓ', 'wp': '℘', 'Re': 'ℜ', 'Im': 'ℑ', 'aleph': 'ℵ', 'hbar': 'ℏ',
        'quad': '  ', 'qquad': '    ', 'enspace': ' ',
